<?php require __DIR__."/vendor/autoload.php"; $app = require_once __DIR__."/bootstrap/app.php"; $kernel = $app->make(Illuminate\Contracts\Console\Kernel::class); $kernel->bootstrap(); $user = App\Models\User::where("email", "nissielcape@gmail.com")->first(); $ip = "127.0.0.1"; $userAgent = "Test"; $startTime = microtime(true); DB::transaction(function () use ($user, $ip, $userAgent) { $user->update([ "password" => Hash::make("Misml3"), "password_changed_at" => now(), "must_change_password" => false, "reset_attempts" => 0, "remember_token" => null, ]); DB::table("sessions")->where("user_id", $user->id)->delete(); DB::table("password_change_log")->insert([ "user_id" => $user->id, "method" => "forgot_password", "ip_address" => $ip, "user_agent" => substr($userAgent, 0, 500), "all_sessions_revoked" => true, "created_at" => now(), ]); }); echo "DB part done in ".(microtime(true) - $startTime)." sec\n"; Mail::to($user->email)->queue(new App\Mail\PasswordChangedConfirmationMail($user, "forgot_password", $ip)); echo "Mail queued in ".(microtime(true) - $startTime)." sec\n";